if (this.inGenerator && this.toks.isContextual("yield")) {
  let node = this.startNode()
  this.next()
  if (this.semicolon() || this.canInsertSemicolon() || (this.tok.type !== tt.star && !this.tok.type.startsExpr)) {
    node.delegate = false
    node.argument = null
  } else {
    node.delegate = this.eat(tt.star)
    node.argument = this.parseMaybeAssign()
  }
  return this.finishNode(node, "YieldExpression")
}

if (prec != null && (!noIn || this.tok.type !== tt._in)) {
  if (prec > minPrec) {
    let node = this.startNodeAt(start)
    node.left = left
    node.operator = this.tok.value
    this.next()
    if (this.curLineStart !== line && this.curIndent < indent && this.tokenStartsLine()) {
      node.right = this.dummyIdent()
    } else {
      let rightStart = this.storeCurrentPos()
      node.right = this.parseExprOp(this.parseMaybeUnary(false), rightStart, prec, noIn, indent, line)
    }
    this.finishNode(node, /&&|\|\||\?\?/.test(node.operator) ? "LogicalExpression" : "BinaryExpression")
    return this.parseExprOp(node, start, minPrec, noIn, indent, line)
  }
}

if (this.eat(tt.star)) {
  if (this.options.ecmaVersion >= 11) {
    if (this.eatContextual("as")) {
      node.exported = this.parseExprAtom()
    } else {
      node.exported = null
    }
  }
  node.source = this.eatContextual("from") ? this.parseExprAtom() : this.dummyString()
  if (this.options.ecmaVersion >= 16)
    node.attributes = this.parseWithClause()
  this.semicolon()
  return this.finishNode(node, "ExportAllDeclaration")
}

if (this.eat(tt._default)) {
  // export default (function foo() {}) // This is FunctionExpression.
  let isAsync
  if (this.tok.type === tt._function || (isAsync = this.toks.isAsyncFunction())) {
    let fNode = this.startNode()
    this.next()
    if (isAsync) this.next()
    node.declaration = this.parseFunction(fNode, "nullableID", isAsync)
  } else if (this.tok.type === tt._class) {
    node.declaration = this.parseClass("nullableID")
  } else {
    node.declaration = this.parseMaybeAssign()
    this.semicolon()
  }
  return this.finishNode(node, "ExportDefaultDeclaration")
}

if (this.tok.type.keyword || this.toks.isLet() || this.toks.isAsyncFunction()) {
  node.declaration = this.parseStatement()
  node.specifiers = []
  node.source = null
} else {
  node.declaration = null
  node.specifiers = this.parseExportSpecifierList()
  node.source = this.eatContextual("from") ? this.parseExprAtom() : null
  if (this.options.ecmaVersion >= 16)
    node.attributes = this.parseWithClause()
  this.semicolon()
}

if (this.tok.type === tt.string) {
  node.specifiers = []
  node.source = this.parseExprAtom()
} else {
  let elt
  if (this.tok.type === tt.name && this.tok.value !== "from") {
    elt = this.startNode()
    elt.local = this.parseIdent()
    this.finishNode(elt, "ImportDefaultSpecifier")
    this.eat(tt.comma)
  }
  node.specifiers = this.parseImportSpecifiers()
  node.source = this.eatContextual("from") && this.tok.type === tt.string ? this.parseExprAtom() : this.dummyString()
  if (elt) node.specifiers.unshift(elt)
}

while (!this.closes(tt.braceR, indent + (this.curLineStart <= continuedLine ? 1 : 0), line)) {
  const attr = this.startNode()
  attr.key = this.tok.type === tt.string ? this.parseExprAtom() : this.parseIdent()
  if (this.eat(tt.colon)) {
    if (this.tok.type === tt.string)
      attr.value = this.parseExprAtom()
    else attr.value = this.dummyString()
  } else {
    if (isDummy(attr.key)) break
    if (this.tok.type === tt.string)
      attr.value = this.parseExprAtom()
    else break
  }
  nodes.push(this.finishNode(attr, "ImportAttribute"))
  this.eat(tt.comma)
}

while (!this.closes(tt.braceR, indent + (this.curLineStart <= continuedLine ? 1 : 0), line)) {
  if (this.isContextual("from")) break
  let elt = this.startNode()
  elt.local = this.parseModuleExportName()
  if (isDummy(elt.local)) break
  elt.exported = this.eatContextual("as") ? this.parseModuleExportName() : elt.local
  this.finishNode(elt, "ExportSpecifier")
  elts.push(elt)
  this.eat(tt.comma)
}

try {
  (function c(node, st, override) {
    let type = override || node.type
    if ((start == null || node.start <= start) &&
        (end == null || node.end >= end))
      visitNode(baseVisitor, type, node, st, c)
    if ((start == null || node.start === start) &&
        (end == null || node.end === end) &&
        test(type, node))
      throw new Found(node, st)
  })(node, state)
} catch (e) {
  if (e instanceof Found) return e
  throw e
}

if (this.options.ecmaVersion >= 6) {
  if (name === "__proto__" && kind === "init") {
    if (propHash.proto) {
      if (refDestructuringErrors) {
        if (refDestructuringErrors.doubleProto < 0) {
          refDestructuringErrors.doubleProto = key.start
        }
      } else {
        this.raiseRecoverable(key.start, "Redefinition of __proto__ property")
      }
    }
    propHash.proto = true
  }
  return
}

if (other) {
  let redefinition
  if (kind === "init") {
    redefinition = this.strict && other.init || other.get || other.set
  } else {
    redefinition = other.init || other[kind]
  }
  if (redefinition)
    this.raiseRecoverable(key.start, "Redefinition of property")
} else {
  other = propHash[name] = {
    init: false,
    get: false,
    set: false
  }
}

while (true) {
  let element = this.parseSubscript(base, startPos, startLoc, noCalls, maybeAsyncArrow, optionalChained, forInit)

  if (element.optional) optionalChained = true
  if (element === base || element.type === "ArrowFunctionExpression") {
    if (optionalChained) {
      const chainNode = this.startNodeAt(startPos, startLoc)
      chainNode.expression = element
      element = this.finishNode(chainNode, "ChainExpression")
    }
    return element
  }

  base = element
}

if (this.type === tt.invalidTemplate) {
  if (!isTagged) {
    this.raiseRecoverable(this.start, "Bad escape sequence in untagged template literal")
  }
  elem.value = {
    raw: this.value.replace(/\r\n?/g, "\n"),
    cooked: null
  }
} else {
  elem.value = {
    raw: this.input.slice(this.start, this.end).replace(/\r\n?/g, "\n"),
    cooked: this.value
  }
}

while (!this.eat(tt.braceR)) {
  if (!first) {
    this.expect(tt.comma)
    if (this.options.ecmaVersion >= 5 && this.afterTrailingComma(tt.braceR)) break
  } else first = false

  const prop = this.parseProperty(isPattern, refDestructuringErrors)
  if (!isPattern) this.checkPropClash(prop, propHash, refDestructuringErrors)
  node.properties.push(prop)
}

if (prop.value.params.length !== paramCount) {
  let start = prop.value.start
  if (prop.kind === "get")
    this.raiseRecoverable(start, "getter should have no params")
  else
    this.raiseRecoverable(start, "setter should have exactly one param")
} else {
  if (prop.kind === "set" && prop.value.params[0].type === "RestElement")
    this.raiseRecoverable(prop.value.params[0].start, "Setter cannot use rest params")
}

if (options.ecmaVersion === "latest") {
  options.ecmaVersion = 1e8
} else if (options.ecmaVersion == null) {
  if (!warnedAboutEcmaVersion && typeof console === "object" && console.warn) {
    warnedAboutEcmaVersion = true
    console.warn("Since Acorn 8.0.0, options.ecmaVersion is required.\nDefaulting to 2020, but this will stop working in the future.")
  }
  options.ecmaVersion = 11
} else if (options.ecmaVersion >= 2015) {
  options.ecmaVersion -= 2009
}

if (this.regexp_eatDecimalEscape(state)) {
  const n = state.lastIntValue
  if (state.switchU) {
    // For SyntaxError in https://www.ecma-international.org/ecma-262/8.0/#sec-atomescape
    if (n > state.maxBackReference) {
      state.maxBackReference = n
    }
    return true
  }
  if (n <= state.numCapturingParens) {
    return true
  }
  state.pos = start
}

while (this.regexp_eatClassAtom(state)) {
  const left = state.lastIntValue
  if (state.eat(0x2D /* - */) && this.regexp_eatClassAtom(state)) {
    const right = state.lastIntValue
    if (state.switchU && (left === -1 || right === -1)) {
      state.raise("Invalid character class")
    }
    if (left !== -1 && right !== -1 && left > right) {
      state.raise("Range out of order in character class")
    }
  }
}

if (this.regexp_eatClassSetCharacter(state)) {
  const left = state.lastIntValue
  if (state.eat(0x2D /* - */) && this.regexp_eatClassSetCharacter(state)) {
    const right = state.lastIntValue
    if (left !== -1 && right !== -1 && left > right) {
      state.raise("Range out of order in character class")
    }
    return true
  }
  state.pos = start
}

if (this.regexp_eatOctalDigit(state)) {
  const n1 = state.lastIntValue
  if (this.regexp_eatOctalDigit(state)) {
    const n2 = state.lastIntValue
    if (n1 <= 3 && this.regexp_eatOctalDigit(state)) {
      state.lastIntValue = n1 * 64 + n2 * 8 + state.lastIntValue
    } else {
      state.lastIntValue = n1 * 8 + n2
    }
  } else {
    state.lastIntValue = n1
  }
  return true
}

if (isFor && !isAwaitUsing && id === "of") {
  // Look ahead for using declaration with initializer, i.e., `for (using of = ...)`
  skipWhiteSpace.lastIndex = next
  const skipAfterOf = skipWhiteSpace.exec(this.input)
  next = next + skipAfterOf[0].length
  if (this.input.charCodeAt(next) !== 61 /* '=' */ ||
    // Check for ==, === and => operators
    (ch = this.input.charCodeAt(next + 1)) === 61 /* '=' */ || ch === 62 /* '>' */) {
    return false
  }
}

if (usingKind) {
  let init = this.startNode()
  this.next()
  if (usingKind === "await using") {
    if (!this.canAwait) {
      this.raise(this.start, "Await using cannot appear outside of async function")
    }
    this.next()
  }
  this.parseVar(init, true, usingKind)
  this.finishNode(init, "VariableDeclaration")
  return this.parseForAfterInit(node, init, awaitAt)
}

if ((this.type === tt._in || (this.options.ecmaVersion >= 6 && this.isContextual("of"))) && init.declarations.length === 1) {
  if (this.type === tt._in) {
    if ((init.kind === "using" || init.kind === "await using") && !init.declarations[0].init) {
      this.raise(this.start, "Using declaration is not allowed in for-in loops")
    }
    if (this.options.ecmaVersion >= 9 && awaitAt > -1) this.unexpected(awaitAt)
  } else if (this.options.ecmaVersion >= 9) node.await = awaitAt > -1
  return this.parseForIn(node, init)
}

if (this.type === tt._catch) {
  let clause = this.startNode()
  this.next()
  if (this.eat(tt.parenL)) {
    clause.param = this.parseCatchClauseParam()
  } else {
    if (this.options.ecmaVersion < 10) this.unexpected()
    clause.param = null
    this.enterScope(0)
  }
  clause.body = this.parseBlock(false)
  this.exitScope()
  node.handler = this.finishNode(clause, "CatchClause")
}

while (this.type !== tt.braceR) {
  const element = this.parseClassElement(node.superClass !== null)
  if (element) {
    classBody.body.push(element)
    if (element.type === "MethodDefinition" && element.kind === "constructor") {
      if (hadConstructor) this.raiseRecoverable(element.start, "Duplicate constructor in the same class")
      hadConstructor = true
    } else if (element.key && element.key.type === "PrivateIdentifier" && isPrivateNameConflicted(privateNameMap, element)) {
      this.raiseRecoverable(element.key.start, `Identifier '#${element.key.name}' has already been declared`)
    }
  }
}

if (keyName) {
  // 'async', 'get', 'set', or 'static' were not a keyword contextually.
  // The last token is any of those. Make it the element name.
  node.computed = false
  node.key = this.startNodeAt(this.lastTokStart, this.lastTokStartLoc)
  node.key.name = keyName
  this.finishNode(node.key, "Identifier")
} else {
  this.parseClassElementName(node)
}

if (this.type === tt._function || (isAsync = this.isAsyncFunction())) {
  let fNode = this.startNode()
  this.next()
  if (isAsync) this.next()
  return this.parseFunction(fNode, FUNC_STATEMENT | FUNC_NULLABLE_ID, false, isAsync)
} else if (this.type === tt._class) {
  let cNode = this.startNode()
  return this.parseClass(cNode, "nullableID")
} else {
  let declaration = this.parseMaybeAssign()
  this.semicolon()
  return declaration
}

if (type === "Identifier")
    this.checkExport(exports, pat, pat.start)
  else if (type === "ObjectPattern")
    for (let prop of pat.properties)
      this.checkPatternExport(exports, prop)
  else if (type === "ArrayPattern")
    for (let elt of pat.elements) {
      if (elt) this.checkPatternExport(exports, elt)
    }
  else if (type === "Property")
    this.checkPatternExport(exports, pat.value)
  else if (type === "AssignmentPattern")
    this.checkPatternExport(exports, pat.left)
  else if (type === "RestElement")
    this.checkPatternExport(exports, pat.argument)

while (!this.eat(tt.braceR)) {
  if (!first) {
    this.expect(tt.comma)
    if (this.afterTrailingComma(tt.braceR)) break
  } else first = false

  const attr = this.parseImportAttribute()
  const keyName = attr.key.type === "Identifier" ? attr.key.name : attr.key.value
  if (hasOwn(attributeKeys, keyName))
    this.raiseRecoverable(attr.key.start, "Duplicate attribute key '" + keyName + "'")
  attributeKeys[keyName] = true
  nodes.push(attr)
}
